+    async fn test_smooth_pacer() {
+        let pacer = SmoothPacer::new(Duration::from_millis(50));
+
+        // First request succeeds
+        assert!(pacer.try_acquire().await);
+
+        // Immediate second request fails
+        assert!(!pacer.try_acquire().await);
+
+        // Wait and try again
+        sleep(Duration::from_millis(60)).await;
+        assert!(pacer.try_acquire().await);
+    }
+}

