+    #[error("Wait time {wait_time:?} exceeds maximum {max_wait:?}")]
+    WaitExceeded {
+        /// Required wait time.
+        wait_time: Duration,
+        /// Maximum allowed wait.
+        max_wait: Duration,
+    },
+
+    /// Invalid configuration.
+    #[error("Invalid rate limit configuration: {0}")]
+    InvalidConfig(String),
+}
